mapper.select:
SELECT alba.alba_id AS albaId, alba.image_id AS imageId, work.work_id AS workId, work.work_status AS workStatus, work.work_date AS workDate, ( SELECT GROUP_CONCAT( DISTINCT CASE s.schedule_time WHEN 'SUNDAY' THEN '일' WHEN 'MONDAY' THEN '월' WHEN 'TUESDAY' THEN '화' WHEN 'WEDNESDAY' THEN '수' WHEN 'THURSDAY' THEN '목' WHEN 'FRIDAY' THEN '금' WHEN 'SATURDAY' THEN '토' ELSE s.schedule_time END ORDER BY FIELD( s.schedule_time, 'SUNDAY','MONDAY','TUESDAY','WEDNESDAY','THURSDAY','FRIDAY','SATURDAY' ) SEPARATOR ',' ) FROM schedule s WHERE s.alba_id = alba.alba_id ) AS scheduleTimes, alba.alba_name AS albaName, alba.alba_phone AS albaPhone, alba.alba_email AS albaEmail, alba.alba_status AS albaStatus FROM alba LEFT JOIN work ON alba.alba_id = work.alba_id
alba.store_id = #{storeId}
ORDER BY alba.alba_id DESC

SELECT COUNT(*) > 0
FROM alba
WHERE alba_id = #{albaId}

SELECT EXISTS (
    SELECT 1 FROM store WHERE store_id = #{storeId}
)

SELECT COUNT(*)
FROM alba
WHERE store_id = #{storeId}
  AND alba_phone = #{albaPhone}
  AND is_active = b'1'

SELECT COUNT(*)
FROM alba
WHERE store_id = #{storeId}
  AND alba_email = #{albaEmail}
  AND is_active = b'1'

mapper.update:
UPDATE alba
store_id = #{storeId}, alba_name = #{albaName}, alba_phone = #{albaPhone}, alba_email = #{albaEmail}, alba_status = #{albaStatus}, updated_at = NOW()
WHERE alba_id = #{albaId}

mapper.select:
SELECT COUNT(*)
FROM alba a
WHERE a.alba_id = #{albaId}
  AND a.store_id = #{storeId}
  AND a.is_active = b'1'
